-- =============================================================
--  AI-Based Career & Major Recommendation System
--  Database: career_recommendation_db
--  Generated for: Final Project Celerates / PT Mitra Talenta Group
-- =============================================================

-- Buat & pilih database
CREATE DATABASE IF NOT EXISTS `career_recommendation_db`
  CHARACTER SET utf8mb4
  COLLATE utf8mb4_unicode_ci;

USE `career_recommendation_db`;

-- Matikan FK checks sementara supaya import lebih cepat
SET FOREIGN_KEY_CHECKS = 0;
SET SQL_MODE = 'NO_AUTO_VALUE_ON_ZERO';

-- ─────────────────────────────────────────────────────────────
-- TABLE 1: student_profiles
-- Deskripsi: Data profil siswa SMA/SMK (training data utama)
-- ─────────────────────────────────────────────────────────────
DROP TABLE IF EXISTS `student_profiles`;
CREATE TABLE `student_profiles` (
  `id`                    INT AUTO_INCREMENT PRIMARY KEY,
  `Student_ID`            VARCHAR(10)  NOT NULL UNIQUE,
  `Nama`                  VARCHAR(100) NOT NULL,
  `Jenis_Kelamin`         ENUM('Laki-laki','Perempuan') NOT NULL,
  `Asal_Sekolah_Tipe`     VARCHAR(20)  NOT NULL COMMENT 'IPA/IPS/SMK-TI/SMK-Kesehatan/SMK-Bisnis',
  `Kota`                  VARCHAR(50),
  `Nilai_Matematika`      TINYINT UNSIGNED,
  `Nilai_Bahasa_Indonesia` TINYINT UNSIGNED,
  `Nilai_Bahasa_Inggris`  TINYINT UNSIGNED,
  `Nilai_IPA`             TINYINT UNSIGNED,
  `Nilai_Fisika`          TINYINT UNSIGNED,
  `Nilai_Kimia`           TINYINT UNSIGNED,
  `Nilai_Biologi`         TINYINT UNSIGNED,
  `Nilai_Ekonomi`         TINYINT UNSIGNED,
  `Nilai_Geografi`        TINYINT UNSIGNED,
  `Nilai_Sosiologi`       TINYINT UNSIGNED,
  `Skor_UN_Rata`          DECIMAL(5,2),
  `Minat_Utama`           VARCHAR(50),
  `Minat_Sekunder`        VARCHAR(50),
  `Tipe_Kepribadian`      ENUM('Analyst','Diplomat','Sentinel','Explorer'),
  `Kemampuan_Analitis`    TINYINT UNSIGNED COMMENT 'Skala 1-10',
  `Kemampuan_Kreatif`     TINYINT UNSIGNED COMMENT 'Skala 1-10',
  `Kemampuan_Sosial`      TINYINT UNSIGNED COMMENT 'Skala 1-10',
  `Kemampuan_Leadership`  TINYINT UNSIGNED COMMENT 'Skala 1-10',
  `Ekskul_Aktif`          VARCHAR(50),
  `Target_Kampus`         VARCHAR(20),
  `Budget_Kuliah`         VARCHAR(30),
  `Jurusan_Label`         VARCHAR(60) COMMENT 'Ground truth label untuk training model',
  `Karir_Label`           VARCHAR(60) COMMENT 'Target karir yang diprediksi',
  INDEX `idx_jurusan_label` (`Jurusan_Label`),
  INDEX `idx_minat_utama`   (`Minat_Utama`),
  INDEX `idx_kota`          (`Kota`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
  COMMENT='Profil siswa SMA/SMK - main training data';

-- Data untuk tabel student_profiles (1200 baris)


-- ─────────────────────────────────────────────────────────────
-- TABLE 2: jurusan_kampus_info
-- Deskripsi: Info jurusan per kampus (lookup/reference table)
-- ─────────────────────────────────────────────────────────────
DROP TABLE IF EXISTS `jurusan_kampus_info`;
CREATE TABLE `jurusan_kampus_info` (
  `id`                      INT AUTO_INCREMENT PRIMARY KEY,
  `Kampus`                  VARCHAR(20)  NOT NULL,
  `Jurusan`                 VARCHAR(60)  NOT NULL,
  `Akreditasi`              ENUM('Unggul','Baik Sekali','Baik'),
  `Daya_Tampung`            SMALLINT UNSIGNED,
  `Passing_Grade_Estimasi`  DECIMAL(4,1),
  `Biaya_Per_Semester_Juta` DECIMAL(5,1),
  `Lokasi_Kota`             VARCHAR(30),
  `Tipe_Kampus`             ENUM('Negeri','Swasta'),
  `Rasio_Dosen_Mahasiswa`   VARCHAR(10),
  `Fasilitas_Lab`           VARCHAR(20),
  `Rating_Kepuasan`         DECIMAL(3,1),
  UNIQUE KEY `uq_kampus_jurusan` (`Kampus`, `Jurusan`),
  INDEX `idx_kampus`  (`Kampus`),
  INDEX `idx_jurusan` (`Jurusan`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
  COMMENT='Info jurusan per kampus - reference table';

-- Data untuk tabel jurusan_kampus_info (110 baris)


-- ─────────────────────────────────────────────────────────────
-- TABLE 3: compatibility_scores
-- Deskripsi: Skor kecocokan siswa vs jurusan (target prediksi)
-- ─────────────────────────────────────────────────────────────
DROP TABLE IF EXISTS `compatibility_scores`;
CREATE TABLE `compatibility_scores` (
  `id`                  INT AUTO_INCREMENT PRIMARY KEY,
  `Student_ID`          VARCHAR(10) NOT NULL,
  `Jurusan`             VARCHAR(60) NOT NULL,
  `Compatibility_Score` DECIMAL(5,2) NOT NULL COMMENT 'Skor 0-100',
  `Label_Cocok`         TINYINT(1)   NOT NULL COMMENT '1=cocok (>=65), 0=tidak cocok',
  INDEX `idx_student`  (`Student_ID`),
  INDEX `idx_jurusan`  (`Jurusan`),
  INDEX `idx_label`    (`Label_Cocok`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
  COMMENT='Skor kecocokan siswa-jurusan untuk training recommender';

-- Data untuk tabel compatibility_scores (1500 baris)


-- ─────────────────────────────────────────────────────────────
-- TABLE 4: career_path
-- Deskripsi: Peta karir per jurusan beserta info pasar kerja
-- ─────────────────────────────────────────────────────────────
DROP TABLE IF EXISTS `career_path`;
CREATE TABLE `career_path` (
  `id`                      INT AUTO_INCREMENT PRIMARY KEY,
  `Jurusan`                 VARCHAR(60) NOT NULL,
  `Karir`                   VARCHAR(60) NOT NULL,
  `Rata_Gaji_Awal_Juta`     DECIMAL(5,1),
  `Rata_Gaji_Senior_Juta`   DECIMAL(5,1),
  `Tingkat_Permintaan_Pasar` ENUM('Sangat Tinggi','Tinggi','Sedang','Rendah'),
  `Skill_Utama`             VARCHAR(200),
  `Sertifikasi_Relevan`     VARCHAR(50),
  `Growth_5yr_Persen`       TINYINT UNSIGNED,
  INDEX `idx_jurusan` (`Jurusan`),
  INDEX `idx_permintaan` (`Tingkat_Permintaan_Pasar`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
  COMMENT='Peta karir dan info pasar kerja per jurusan';

-- Data untuk tabel career_path (68 baris)


-- ─────────────────────────────────────────────────────────────
-- TABLE 5: jurusan_metadata
-- Deskripsi: Metadata jurusan untuk chatbot & tampilan UI
-- ─────────────────────────────────────────────────────────────
DROP TABLE IF EXISTS `jurusan_metadata`;
CREATE TABLE `jurusan_metadata` (
  `id`               INT AUTO_INCREMENT PRIMARY KEY,
  `jurusan`          VARCHAR(60)   NOT NULL UNIQUE,
  `deskripsi`        TEXT,
  `prospek_karir`    TEXT          COMMENT 'Comma-separated list',
  `skill_dibutuhkan` VARCHAR(200)  COMMENT 'Comma-separated list',
  `minat_cocok`      VARCHAR(50),
  `kepribadian_cocok` VARCHAR(20),
  INDEX `idx_jurusan` (`jurusan`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
  COMMENT='Metadata jurusan untuk chatbot RAG dan tampilan UI';

-- Data untuk tabel jurusan_metadata (20 baris)


